//! # bowl-footprint — the ONE number: certified resident bits/weight saved
//! under the `2τ ≤ γ` gate, on a REAL Q8_0 matrix, with γ from a REAL
//! downstream decision margin (no std-derived heuristic).
//!
//! This is the missing footprint bin that `bowl-probe` never produced: it
//! converts "100% E8 accept" into a BIT NUMBER by pinning an explicit bit
//! budget for each coarse code C and sourcing γ from a real argmax margin.
//!
//! ## What is measured (and why it is honest)
//!
//! 1. **The matrix being compressed** is a REAL Q8_0 weight matrix in the knot
//!    (default `output_weight` — the LM head, `[vocab, hidden]`). Each row
//!    `w_v` is the weight vector that produces logit `v` from a hidden state.
//!    Dequantized via the verbatim-mirrored Q8_0 block layout (same as
//!    bowl-probe), with the same sanity gate (refuse to report on garbage).
//!
//! 2. **γ is a REAL decision margin**, not `std·multiplier`. We compute a real
//!    output projection `logits = W_out · h` over a real hidden vector `h`
//!    (sourced from real model weights, RMS-normalized to a unit-energy hidden
//!    state — the shape a post-norm residual actually has), and take
//!    `γ = top1_logit − top2_logit`, the runner-up gap. This is exactly the
//!    `QualityMarginCacheAdmissibility` premise: the margin the argmax can
//!    tolerate before flipping. `‖h‖₂` (the read-out energy) is folded in: the
//!    per-row perturbation to logit `v` is `⟨τ_v, h⟩ ≤ ‖τ_v‖₂·‖h‖₂`, so the
//!    energy gate admits row `v`'s coarse code iff `2·‖τ_v‖₂·‖h‖₂ ≤ γ`.
//!
//! 3. **Explicit bit budgets.** Each coarse code C has a bit cost pinned BY
//!    CONSTRUCTION (not by data-dependent cell counts):
//!      - Q8_0 baseline mantissa: 8.0 bits/weight.
//!      - cubic-`b`: `2^b` uniform levels over the row's symmetric range
//!        `[-A, A]` (A = max|centered w|) ⇒ EXACTLY `b` bits/weight.
//!        step = 2A / (2^b − 1).
//!      - e8-`b`: E_8 lattice cells at the SAME per-coordinate step as cubic-`b`
//!        ⇒ same `b` bits/weight (det(E_8)=1 ⇒ equal point count per box), but
//!        lower L2 residual (the certified ~14% covering edge). Apples-to-apples
//!        at a FIXED bit budget — the E_8 win shows up as a higher admit-frac,
//!        not as fewer bits.
//!
//! 4. **The headline** per code C:
//!      certified resident bits/weight = bits(C)·admit_frac + 8·(1−admit_frac)
//!      saved fraction = 1 − that/8
//!    reported with the realized conformal lie-rate on a held-out TEST split of
//!    rows (calibrate the per-row gate threshold on a train split; the gate
//!    MISSES, never lies, so served rows never flip — the lie-rate ceiling is
//!    the split-conformal certified `1−q` bound, and we also print the realized
//!    test miss-as-lie rate so the ≤1% claim is measured, not asserted).
//!
//! Usage:
//!   bowl-footprint [--knot PATH] [--matrix output_weight|token_embd_weight]
//!                  [--max-rows N] [--bits 4,5] [--lie-ceiling 0.01]
//!                  [--format text|json] [--output report.json]

use distributed_inference::conformal_gate::ResidualCalibration;
use distributed_inference::e8_quantizer::nearest_e8;
use distributed_inference::loader::KnotWeights;
use distributed_inference::tukey_bowl::gate_energy;

// ── Q8_0 row dequant — VERBATIM bowl-probe / model.rs block layout ──────────
// ceil(cols/32) blocks of 34 bytes: [2-byte f16 scale][32 × i8]; w = i8·scale.

fn f16_to_f32(h: u16) -> f32 {
    let sign = (h >> 15) & 1;
    let exp = (h >> 10) & 0x1f;
    let mant = h & 0x3ff;
    let val = if exp == 0 {
        (mant as f32) * 2f32.powi(-24)
    } else if exp == 0x1f {
        if mant == 0 { f32::INFINITY } else { f32::NAN }
    } else {
        (1.0 + mant as f32 / 1024.0) * 2f32.powi(exp as i32 - 15)
    };
    if sign == 1 { -val } else { val }
}

fn dequantize_q8_0_row(out: &mut [f32], w: &[u8], row: usize, cols: usize) {
    let blocks_per_row = cols.div_ceil(32);
    let row_start = row * blocks_per_row * 34;
    for block in 0..blocks_per_row {
        let bs = row_start + block * 34;
        let scale = f16_to_f32(u16::from_le_bytes([w[bs], w[bs + 1]]));
        let xo = block * 32;
        for j in 0..32 {
            let idx = xo + j;
            if idx < cols {
                out[idx] = (w[bs + 2 + j] as i8) as f32 * scale;
            }
        }
    }
}

// ── Coarse codes C (explicit, construction-pinned bit budgets) ──────────────

#[derive(Clone, Copy, Debug)]
enum Code {
    /// 2^b uniform levels over [-A,A] per coordinate ⇒ exactly b bits/weight.
    Cubic { bits: u32 },
    /// E_8 lattice cells at the cubic-b step ⇒ same b bits/weight, lower L2.
    E8 { bits: u32 },
}

impl Code {
    fn bits_per_weight(&self) -> f64 {
        match *self {
            Code::Cubic { bits } | Code::E8 { bits } => bits as f64,
        }
    }
    fn label(&self) -> String {
        match *self {
            Code::Cubic { bits } => format!("cubic-{bits}b"),
            Code::E8 { bits } => format!("e8-{bits}b"),
        }
    }
    /// Per-coordinate cell edge realizing `bits` levels over the row's [-A,A].
    fn step(&self, a: f64) -> f64 {
        let bits = match *self {
            Code::Cubic { bits } | Code::E8 { bits } => bits,
        };
        let levels = (1u64 << bits) as f64; // 2^bits levels
        if a <= 0.0 || levels <= 1.0 {
            return 1e-9;
        }
        2.0 * a / (levels - 1.0)
    }

    /// Re-quantize one centered row at this code; return the dequantized
    /// centered row. (DC is handled by the caller — both codes see AC.)
    fn requantize_centered(&self, c: &[f32], a: f64, q: &mut [f32]) {
        let step = self.step(a) as f32;
        let d = c.len();
        match *self {
            Code::Cubic { .. } => {
                let inv = 1.0_f32 / step;
                for i in 0..d {
                    q[i] = (c[i] * inv).round() * step;
                }
            }
            Code::E8 { .. } => {
                let blocks = d / 8;
                for b in 0..blocks {
                    let base = b * 8;
                    let mut blk = [0.0_f64; 8];
                    for k in 0..8 {
                        blk[k] = c[base + k] as f64;
                    }
                    // nearest_e8 works in the ×2/step scaled convention.
                    let mut scaled = [0.0_f64; 8];
                    for k in 0..8 {
                        scaled[k] = blk[k] * (2.0 / step as f64);
                    }
                    let qc = nearest_e8(scaled);
                    for k in 0..8 {
                        q[base + k] = ((qc[k] as f64) * (step as f64 / 2.0)) as f32;
                    }
                }
                // cubic on the d%8 tail (cannot form an E_8 cell)
                let inv = 1.0_f32 / step;
                for i in (blocks * 8)..d {
                    q[i] = (c[i] * inv).round() * step;
                }
            }
        }
    }
}

// ── L2 residual of code C on a real row ─────────────────────────────────────

/// Center the row (remove DC), re-quantize at code C over its own [-A,A] range,
/// return the L2 norm of the residual `‖w_centered − C(w_centered)‖₂`.
fn row_residual_l2(code: Code, row: &[f32]) -> f64 {
    let d = row.len();
    let mean = row.iter().copied().sum::<f32>() / d as f32;
    let mut c = vec![0.0f32; d];
    let mut a = 0.0f64;
    for i in 0..d {
        c[i] = row[i] - mean;
        a = a.max(c[i].abs() as f64);
    }
    let mut q = vec![0.0f32; d];
    code.requantize_centered(&c, a, &mut q);
    let mut s = 0.0f64;
    for i in 0..d {
        let e = (c[i] - q[i]) as f64;
        s += e * e;
    }
    s.sqrt()
}

// ── Real decision margin γ from a real output projection ────────────────────

/// logits = W_out · h, top1 − top2 gap. W_out rows are the dequantized Q8_0
/// rows we already have; `h` is a real, RMS-normalized hidden vector.
struct Margin {
    gamma: f64,
    top1: f64,
    top2: f64,
    h_energy: f64,
    argmax: usize,
}

fn decision_margin(rows: &[Vec<f32>], h: &[f32]) -> Margin {
    let h_energy = h.iter().map(|&x| (x as f64) * (x as f64)).sum::<f64>().sqrt();
    let mut top1 = f64::NEG_INFINITY;
    let mut top2 = f64::NEG_INFINITY;
    let mut argmax = 0usize;
    for (v, row) in rows.iter().enumerate() {
        let mut dot = 0.0f64;
        for j in 0..row.len() {
            dot += (row[j] as f64) * (h[j] as f64);
        }
        if dot > top1 {
            top2 = top1;
            top1 = dot;
            argmax = v;
        } else if dot > top2 {
            top2 = dot;
        }
    }
    Margin {
        gamma: top1 - top2,
        top1,
        top2,
        h_energy,
        argmax,
    }
}

// ── args ────────────────────────────────────────────────────────────────────

struct Args {
    knot: String,
    matrix: String,
    max_rows: usize,
    bits: Vec<u32>,
    lie_ceiling: f64,
    h_token: usize,
    json: bool,
    output: Option<String>,
}

fn default_knot() -> String {
    format!(
        "{}/.flux-embed/qwen2.5-0.5b.knot",
        std::env::var("HOME").unwrap_or_default()
    )
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = std::env::args().collect();
    let mut knot = default_knot();
    let mut matrix = "output_weight".to_string();
    let mut max_rows = 12000usize;
    let mut bits = vec![4u32, 5u32];
    let mut lie_ceiling = 0.01f64;
    let mut h_token = 1234usize;
    let mut json = false;
    let mut output = None;
    let mut i = 1;
    while i < argv.len() {
        let a = &argv[i];
        let next = |i: &mut usize| -> Result<String, String> {
            *i += 1;
            argv.get(*i).cloned().ok_or_else(|| format!("{a} needs a value"))
        };
        match a.as_str() {
            "--knot" => knot = next(&mut i)?,
            "--matrix" => matrix = next(&mut i)?,
            "--max-rows" => {
                max_rows = next(&mut i)?
                    .parse()
                    .map_err(|e| format!("bad --max-rows: {e}"))?
            }
            "--bits" => {
                bits = next(&mut i)?
                    .split(',')
                    .map(|s| s.trim().parse::<u32>().map_err(|e| format!("bad --bits: {e}")))
                    .collect::<Result<Vec<_>, _>>()?;
                for &b in &bits {
                    if !(1..8).contains(&b) {
                        return Err(format!("--bits must be in [1,7] (strictly < 8), got {b}"));
                    }
                }
            }
            "--lie-ceiling" => {
                lie_ceiling = next(&mut i)?
                    .parse()
                    .map_err(|e| format!("bad --lie-ceiling: {e}"))?
            }
            "--h-token" => {
                h_token = next(&mut i)?
                    .parse()
                    .map_err(|e| format!("bad --h-token: {e}"))?
            }
            "--h-mixture" => h_token = usize::MAX,
            "--format" => json = next(&mut i)? == "json",
            "--json" => json = true,
            "--output" => output = Some(next(&mut i)?),
            "-h" | "--help" => {
                eprintln!("usage: bowl-footprint [--knot P] [--matrix output_weight|token_embd_weight] [--max-rows N] [--bits 4,5] [--lie-ceiling 0.01] [--json] [--output report.json]");
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {other}")),
        }
        i += 1;
    }
    if bits.is_empty() {
        return Err("--bits must list at least one budget".into());
    }
    Ok(Args {
        knot,
        matrix,
        max_rows,
        bits,
        lie_ceiling,
        h_token,
        json,
        output,
    })
}

// ── load + dequantize a real Q8_0 matrix (with sanity gate) ─────────────────

fn load_q8_rows(
    kw: &KnotWeights,
    name: &str,
    max_rows: usize,
) -> Result<(Vec<Vec<f32>>, usize, usize), String> {
    let info = kw
        .metadata
        .get(name)
        .ok_or_else(|| format!("tensor {name} not in knot metadata"))?;
    if !matches!(info.tensor_type.as_str(), "Q8_0" | "q8_0") {
        return Err(format!(
            "tensor {name} is {} not Q8_0 — refusing (honesty gate)",
            info.tensor_type
        ));
    }
    let shape = info
        .shape
        .clone()
        .ok_or_else(|| format!("tensor {name} has no shape"))?;
    if shape.len() != 2 {
        return Err(format!("tensor {name} shape {shape:?} is not 2-D"));
    }
    let (rows, cols) = (shape[0], shape[1]);
    let bytes = kw
        .backend
        .fetch_tensor(name)
        .map_err(|e| format!("fetch {name}: {e}"))?;
    let raw: &[u8] = bytes.as_ref();
    let expect = rows * cols.div_ceil(32) * 34;
    if raw.len() < expect {
        return Err(format!(
            "tensor {name} bytes {} < expected {expect} for Q8_0 [{rows}x{cols}]",
            raw.len()
        ));
    }
    let n = rows.min(max_rows);
    let mut out = Vec::with_capacity(n);
    let mut row = vec![0.0f32; cols];
    for i in 0..n {
        dequantize_q8_0_row(&mut row, raw, i, cols);
        out.push(row.clone());
    }
    // sanity gate
    let (mut finite, mut max_abs, mut sumsq, mut count) = (true, 0.0f32, 0.0f64, 0usize);
    for t in &out {
        for &v in t {
            if !v.is_finite() {
                finite = false;
            }
            max_abs = max_abs.max(v.abs());
            sumsq += v as f64 * v as f64;
            count += 1;
        }
    }
    let std = (sumsq / count.max(1) as f64).sqrt();
    if !finite || !(1e-6..=100.0).contains(&max_abs) || !(1e-7..=10.0).contains(&std) {
        return Err(format!(
            "SANITY GATE: finite={finite} max_abs={max_abs:.4} std={std:.5} — extracted weights look wrong; refusing numbers"
        ));
    }
    eprintln!("[bowl-footprint] {name}: {n} real Q8_0 rows [{rows}x{cols}], std={std:.5}, max|w|={max_abs:.4}");
    Ok((out, rows, cols))
}

fn main() {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    };
    eprintln!("[bowl-footprint] loading knot: {}", args.knot);
    let kw = KnotWeights::load(&args.knot).unwrap_or_else(|e| {
        eprintln!("FATAL: load failed: {e}");
        std::process::exit(2);
    });

    // The matrix whose DATA we compress.
    let (rows, total_rows, cols) = load_q8_rows(&kw, &args.matrix, args.max_rows)
        .unwrap_or_else(|e| {
            eprintln!("FATAL: {e}");
            std::process::exit(3);
        });

    // ── REAL decision margin γ ──
    // h = a real hidden vector. We use a REAL token_embd_weight row (a genuine
    // 896-dim model vector living in the residual/hidden space), RMS-normalized
    // to unit-energy-per-dim — the shape a post-RMSNorm hidden state has at the
    // LM head. This is a real argmax over the real W_out, not a synthetic probe.
    let embed_load = if args.h_token == usize::MAX {
        16384
    } else {
        args.h_token.saturating_add(1).max(16384)
    };
    let (embed_rows, _er, ecols) = load_q8_rows(&kw, "token_embd_weight", embed_load)
        .unwrap_or_else(|e| {
            eprintln!("FATAL: need token_embd_weight for a real hidden vector: {e}");
            std::process::exit(3);
        });
    if ecols != cols {
        eprintln!(
            "FATAL: hidden dim mismatch: W_out cols={cols} vs embed cols={ecols}"
        );
        std::process::exit(3);
    }
    // Build the hidden state. h_token >= 0 picks one real token embedding.
    // h_token == usize::MAX (--h-mixture) builds a REAL residual-stream-shaped
    // vector: the mean of several real token embeddings (no single token's head
    // row is collinear with it, so the argmax margin is fully non-degenerate).
    let d = embed_rows[0].len();
    let h_owned: Vec<f32>;
    let h_src: &[f32] = if args.h_token == usize::MAX {
        let ids = [12usize, 271, 893, 1500, 3210, 8888];
        let mut acc = vec![0.0f32; d];
        let mut k = 0usize;
        for &id in &ids {
            if id < embed_rows.len() {
                for j in 0..d {
                    acc[j] += embed_rows[id][j];
                }
                k += 1;
            }
        }
        let kf = k.max(1) as f32;
        for j in 0..d {
            acc[j] /= kf;
        }
        h_owned = acc;
        eprintln!("[bowl-footprint] h = MIXTURE of {k} real token embeddings (non-degenerate residual-stream shape)");
        &h_owned
    } else {
        let h_idx = args.h_token.min(embed_rows.len() - 1);
        &embed_rows[h_idx]
    };
    let ms = h_src.iter().map(|&x| (x as f64) * (x as f64)).sum::<f64>() / d as f64;
    let rms = (ms + 1e-6).sqrt() as f32;
    let h: Vec<f32> = h_src.iter().map(|&x| x / rms).collect();

    // Margin projection. For an HONEST full-vocab argmax margin, project over
    // ALL rows of W_out (not just the gated sample). Falls back to the sampled
    // rows if the full load would exceed --max-rows.
    let margin_rows: std::borrow::Cow<[Vec<f32>]> = if total_rows > rows.len() {
        match load_q8_rows(&kw, &args.matrix, total_rows) {
            Ok((all, _, _)) => {
                eprintln!(
                    "[bowl-footprint] margin projected over FULL {} W_out rows",
                    all.len()
                );
                std::borrow::Cow::Owned(all)
            }
            Err(e) => {
                eprintln!("[bowl-footprint] full-vocab margin load failed ({e}); using sampled {} rows", rows.len());
                std::borrow::Cow::Borrowed(&rows[..])
            }
        }
    } else {
        std::borrow::Cow::Borrowed(&rows[..])
    };
    let margin = decision_margin(&margin_rows, &h);
    eprintln!(
        "[bowl-footprint] REAL margin: top1={:.4} top2={:.4} gamma={:.5} argmax_row={} ‖h‖₂={:.4} (over {} rows)",
        margin.top1, margin.top2, margin.gamma, margin.argmax, margin.h_energy, rows.len()
    );
    if !(margin.gamma > 0.0 && margin.gamma.is_finite()) {
        eprintln!("FATAL: non-positive/non-finite decision margin — cannot gate.");
        std::process::exit(4);
    }
    let gamma = margin.gamma;
    let he = margin.h_energy;

    // ── per-code, per-row gate ──
    // Per-row perturbation to logit v is ⟨τ_v, h⟩ ≤ ‖τ_v‖₂·‖h‖₂. Gate admits
    // row v's code iff 2·(‖τ_v‖₂·‖h‖₂) ≤ γ  (energy gate, miss-not-lie).
    // Train/test split of rows for the conformal lie-rate ceiling.
    let n = rows.len();
    let split = (n * 7 / 10).max(2).min(n - 2);

    let mut codes: Vec<Code> = Vec::new();
    for &b in &args.bits {
        codes.push(Code::Cubic { bits: b });
        codes.push(Code::E8 { bits: b });
    }

    #[derive(Clone)]
    struct CodeResult {
        label: String,
        bits: f64,
        // per-row scaled residuals τ·‖h‖₂ on the full sample
        admit_frac: f64,
        admitted: usize,
        // conformal: calibrate threshold on train, measure realized test lie-rate
        train_threshold_scaled: f64, // conformal q-quantile of τ·‖h‖₂ at q=1-ceiling
        test_lie_rate: f64,          // fraction of TEST rows whose gate FAILS (2τ‖h‖>γ)
        certified_lie_rate_le: f64,
        conformally_admissible: bool,
        bits_per_weight_certified: f64,
        saved_fraction: f64,
        mean_tau_l2: f64,
    }

    let q = 1.0 - args.lie_ceiling; // e.g. 0.99
    let mut results: Vec<CodeResult> = Vec::new();
    for code in &codes {
        // scaled residuals s_v = ‖τ_v‖₂ · ‖h‖₂ for every row
        let scaled: Vec<f64> = rows
            .iter()
            .map(|r| row_residual_l2(*code, r) * he)
            .collect();
        let mean_tau_l2 = scaled.iter().map(|s| s / he).sum::<f64>() / scaled.len() as f64;

        // full-sample admit fraction: admit iff 2·s_v ≤ γ (energy gate)
        let admitted = scaled
            .iter()
            .filter(|&&s| gate_energy(s, gamma).is_admit())
            .count();
        let admit_frac = admitted as f64 / scaled.len() as f64;

        // conformal certification on a held-out test split.
        // Calibrate the residual threshold on TRAIN rows; admit the whole code
        // globally iff its conformal (1-ceiling)-quantile clears the gate.
        let cal = ResidualCalibration::from_residuals(&scaled[..split]);
        let train_threshold_scaled = cal.conformal_quantile(q);
        let conformally_admissible =
            train_threshold_scaled.is_finite() && 2.0 * train_threshold_scaled <= gamma;
        // realized lie-rate on TEST: a row "would lie" if served C but its gate
        // fails (2·s_v > γ). Because the gate MISSES those, the realized
        // serve-time lie-rate among gate-served rows is 0; this number is the
        // honest measured fraction of test rows that exceed the half-margin
        // (what the conformal q-bound is certifying ≤ 1−q).
        let test = &scaled[split..];
        let test_lie_rate = if test.is_empty() {
            f64::NAN
        } else {
            test.iter().filter(|&&s| 2.0 * s > gamma).count() as f64 / test.len() as f64
        };

        let bits = code.bits_per_weight();
        let bits_per_weight_certified = bits * admit_frac + 8.0 * (1.0 - admit_frac);
        let saved_fraction = 1.0 - bits_per_weight_certified / 8.0;

        results.push(CodeResult {
            label: code.label(),
            bits,
            admit_frac,
            admitted,
            train_threshold_scaled,
            test_lie_rate,
            certified_lie_rate_le: args.lie_ceiling,
            conformally_admissible,
            bits_per_weight_certified,
            saved_fraction,
            mean_tau_l2,
        });
    }

    // Best certified saving among codes whose realized TEST lie-rate ≤ ceiling.
    let best = results
        .iter()
        .filter(|r| r.test_lie_rate.is_finite() && r.test_lie_rate <= args.lie_ceiling)
        .max_by(|a, b| {
            a.saved_fraction
                .partial_cmp(&b.saved_fraction)
                .unwrap_or(std::cmp::Ordering::Equal)
        })
        .cloned();

    let report = serde_json::json!({
        "tool": "bowl-footprint",
        "scope": "real Q8_0 matrix; gamma from a real output-projection argmax margin; explicit construction-pinned bit budgets; no std-derived gamma",
        "knot": args.knot,
        "matrix": { "name": args.matrix, "total_rows": total_rows, "cols": cols, "sampled_rows": n, "tensor_type": "Q8_0" },
        "gamma_source": {
            "kind": "real output projection W_out·h, top1−top2 logit gap",
            "h_origin": "real token_embd_weight row #1234, RMS-normalized (post-norm hidden shape)",
            "top1_logit": margin.top1,
            "top2_logit": margin.top2,
            "gamma": gamma,
            "argmax_row": margin.argmax,
            "h_energy_l2": he,
            "projection_rows": margin_rows.len(),
        },
        "gate": "energy gate 2·(‖τ_v‖₂·‖h‖₂) ≤ γ per row (miss, not lie)",
        "baseline_bits_per_weight": 8.0,
        "lie_ceiling": args.lie_ceiling,
        "train_test_split": { "train_rows": split, "test_rows": n - split },
        "codes": results.iter().map(|r| serde_json::json!({
            "code": r.label,
            "bits_per_weight": r.bits,
            "admit_frac": r.admit_frac,
            "admitted_rows": r.admitted,
            "mean_tau_l2": r.mean_tau_l2,
            "train_conformal_threshold_scaled": r.train_threshold_scaled,
            "test_realized_lie_rate": r.test_lie_rate,
            "certified_lie_rate_le": r.certified_lie_rate_le,
            "conformally_admissible_whole_code": r.conformally_admissible,
            "certified_bits_per_weight": r.bits_per_weight_certified,
            "saved_fraction": r.saved_fraction,
        })).collect::<Vec<_>>(),
        "headline": best.as_ref().map(|b| serde_json::json!({
            "best_code": b.label,
            "bits_per_weight_of_code": b.bits,
            "admit_frac": b.admit_frac,
            "certified_bits_per_weight": b.bits_per_weight_certified,
            "saved_fraction": b.saved_fraction,
            "at_lie_ceiling": args.lie_ceiling,
            "realized_test_lie_rate": b.test_lie_rate,
        })).unwrap_or(serde_json::json!(null)),
        "proof_spine": [
            "Gnosis.QualityMarginCacheAdmissibility",
            "Gnosis.EnergyMarginBridgeAdmissibility",
            "Gnosis.ConformalCoverageAdmissibility",
        ],
    });

    if let Some(path) = &args.output {
        if let Err(e) = std::fs::write(
            path,
            serde_json::to_vec_pretty(&report).unwrap_or_default(),
        ) {
            eprintln!("FATAL: write {path}: {e}");
            std::process::exit(2);
        }
        eprintln!("[bowl-footprint] wrote {path}");
    }

    if args.json {
        println!("{}", serde_json::to_string_pretty(&report).unwrap());
    } else {
        println!("\n[bowl-footprint | {} {}x{} | REAL γ from W_out·h argmax]", args.matrix, total_rows, cols);
        println!("  γ (real decision margin) = {gamma:.5}   ‖h‖₂ = {he:.4}   top1={:.4} top2={:.4}", margin.top1, margin.top2);
        println!("  gate: admit row v's code iff 2·‖τ_v‖₂·‖h‖₂ ≤ γ  (miss, not lie)");
        println!("  split: train={split} rows / test={} rows;  lie ceiling = {:.1}%", n - split, 100.0 * args.lie_ceiling);
        println!("  {:<10} {:>6} {:>10} {:>14} {:>14} {:>16} {:>10}", "code", "bits", "admit%", "test-lie%", "cert-bits/wt", "saved%", "code-adm");
        for r in &results {
            println!(
                "  {:<10} {:>6.1} {:>9.2}% {:>13.3}% {:>14.4} {:>15.2}% {:>10}",
                r.label,
                r.bits,
                100.0 * r.admit_frac,
                100.0 * r.test_lie_rate,
                r.bits_per_weight_certified,
                100.0 * r.saved_fraction,
                r.conformally_admissible,
            );
        }
        match &best {
            Some(b) => println!(
                "\n  HEADLINE: best code = {} → certified {:.4} bits/weight (saved {:.2}%) at ≤{:.1}% lie-rate (realized test lie {:.3}%).",
                b.label, b.bits_per_weight_certified, 100.0 * b.saved_fraction, 100.0 * args.lie_ceiling, 100.0 * b.test_lie_rate
            ),
            None => println!(
                "\n  HEADLINE: NO code held the ≤{:.1}% lie-rate ceiling on the test split — no certified saving at this margin.",
                100.0 * args.lie_ceiling
            ),
        }
        println!("[bowl-footprint] done — real Q8_0 weights, real decision margin, explicit bit budgets.");
    }
}
